mapper.select:
SELECT DISTINCT f.id, f.original_name, f.stored_name, f.storage_path, f.mime_type, f.file_size, f.file_category, f.description, f.created_at FROM knowledge_file f
INNER JOIN file_tag ft ON f.id = ft.file_id AND ft.tag_id = #{tagId}
AND f.file_category = #{fileCategory}
AND f.original_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY f.created_at DESC
